36	import { ref, reactive, watch, onMounted } from 'vue'
37	import { useRoute, useRouter } from 'vue-router'
38	import { useFlows } from '@/composables/useFlows'
39	import { getDefinition } from '@/api/definitions'
40	import DynamicFormField from '@/components/DynamicFormField.vue'
41	import type { WorkflowDefinition } from '@/api/models'
42	import { useAuthStore } from '@/stores/auth'
43	import { useErrorHandler } from '@/composables/useErrorHandler'
44	
45	const route = useRoute()
46	const router = useRouter()
47	const auth = useAuthStore()
48	const { handleError } = useErrorHandler()
49	const { submitFlow, isLoading } = useFlows()
50	
51	const SESSION_KEY = 'submitFormDraft'
52	
53	const definition = ref<WorkflowDefinition | undefined>(undefined)
54	const formData = reactive<Record<string, string>>({})
55	const fieldErrors = reactive<Record<string, string>>({})
56	const submitError = ref<string | null>(null)
57	
58	onMounted(() => {
59	  const id = route.params.definitionId as string
60	  definition.value = getDefinition(id)
61	
62	  // FR-002: guard — only initiators may submit
63	  if (definition.value && !auth.isInGroup(definition.value.initiatorGroup)) {
64	    router.replace({ name: 'my-submissions' })
65	    return
66	  }
67	
68	  // T049: restore draft saved before session expiry redirect
69	  const saved = sessionStorage.getItem(SESSION_KEY)
70	  if (saved) {
71	    try {
72	      const draft = JSON.parse(saved) as Record<string, string>
73	      Object.assign(formData, draft)
74	    } catch {
75	      // ignore corrupt draft
76	    }
77	    sessionStorage.removeItem(SESSION_KEY)
78	  }
79	})
80	
81	function validate(): boolean {
82	  let valid = true
83	  for (const key in fieldErrors) delete fieldErrors[key]
84	
85	  for (const field of definition.value?.fields ?? []) {
86	    if (field.required && !formData[field.name]?.trim()) {
87	      fieldErrors[field.name] = `${field.label} is required.`
88	      valid = false
89	    }
90	  }
91	  return valid
92	}
93	
94	// Persist draft on every change so auth-redirect doesn't lose progress (T049)
95	watch(formData, (data) => {
96	  if (Object.keys(data).length) {
97	    sessionStorage.setItem(SESSION_KEY, JSON.stringify(data))
98	  }
99	}, { deep: true })
100	
101	async function onSubmit(): Promise<void> {
102	  if (!definition.value || !validate()) return
103	  submitError.value = null
104	  try {
105	    const flow = await submitFlow({
106	      definitionId: definition.value.definitionId,
107	      formData: { ...formData },
108	    })
109	    sessionStorage.removeItem(SESSION_KEY)
110	    await router.push({ name: 'flow-detail', params: { flowId: flow.flowId } })
111	  } catch (e) {
112	    submitError.value = handleError(e)
113	  }
114	}
